package com.samudhra.certificates.entity;
import jakarta.persistence.*; import java.time.LocalDate;
@Entity @Table(name="certificates", indexes={@Index(columnList="certificateNumber", unique=true),@Index(columnList="organization_id")}) public class Certificate extends BaseEntity {
  @ManyToOne(fetch=FetchType.LAZY, optional=false) private Organization organization; @ManyToOne(fetch=FetchType.LAZY) private Student student; @ManyToOne(fetch=FetchType.LAZY) private Template template; @Column(nullable=false,unique=true) private String certificateNumber; private LocalDate issueDate; private String status="VALID"; @Lob @Column(columnDefinition="LONGTEXT") private String snapshotJson; private String pdfUrl; private String pngUrl;
  public Organization getOrganization(){return organization;} public void setOrganization(Organization v){organization=v;} public Student getStudent(){return student;} public void setStudent(Student v){student=v;} public Template getTemplate(){return template;} public void setTemplate(Template v){template=v;} public String getCertificateNumber(){return certificateNumber;} public void setCertificateNumber(String v){certificateNumber=v;} public LocalDate getIssueDate(){return issueDate;} public void setIssueDate(LocalDate v){issueDate=v;} public String getStatus(){return status;} public void setStatus(String v){status=v;} public String getSnapshotJson(){return snapshotJson;} public void setSnapshotJson(String v){snapshotJson=v;} public String getPdfUrl(){return pdfUrl;} public void setPdfUrl(String v){pdfUrl=v;} public String getPngUrl(){return pngUrl;} public void setPngUrl(String v){pngUrl=v;}
}
